import React from 'react';

class ContactForm extends React.Component {
  constructor(props){
      super(props);
      this.URL = "https://script.google.com/macros/s/AKfycbxK2MdwVTDU6snWstKn6yBmlwE1GsqCUDdL38PRMc14eaaPniPf/exec";
    }
    changeHandler = (e) => {
        let id = e.target.id;
        let val = e.target.value;
        let s = {};
        s[id] = val
        this.setState(s);
    }
    clickHandler = (e) => {
        this.submitFormData(e);
    }
    setUpXmlHttpRequest() {
        let xhr = new XMLHttpRequest();
        xhr.open('post', this.URL);
        xhr.onload = function() {
            if(xhr.status !== 200)
            {
                return alert("Unexpected response");
            }

            const response = JSON.parse(xhr.responseText);
            if (response.message === 0)
            {
                return console.log(response.error);
            }
            return console.log(response);
        };
        return xhr;
    }
    submitFormData(e){
        e.preventDefault();
        const data = new FormData();
        data.append('timestamp',this.state.name);
        data.append('name',this.state.name);
        data.append('email',this.state.email);
        data.append('message',this.state.message);
        console.log(data);
        let xhr = this.setUpXmlHttpRequest();
        xhr.send(data);
        
    }
    render() {
        return(
            <form>
                <input type='text' className="input-box" id='name' placeholder="what's your name?" onChange={this.changeHandler}/>
                <input type='email' className="input-box" id='email' placeholder="email address" onChange={this.changeHandler} />
                <textarea id="message" className="input-box" name="message" placeholder="send me a message" onChange={this.changeHandler} />
                <input id="submitbutton" className="button" type="submit" value="submit" onClick={this.clickHandler}></input>
            </form>
        )
    }
}

export default ContactForm;