class PortfolioSection extends React.Component {

    constructor(props){
        super(props);
        this.state = {
            activeSkill:undefined
        }
        this.skills = [
            {
                name:"Excel&VBA",
                percentage:95
            },
            {
                name:"Google scripts",
                percentage:75
            },
            {
                name:"JavaScript",
                percentage:75
            },
            {
                name:"Python",
                percentage:50
            },
            {
                name:"Web development",
                percentage:65
            },
            {
                name:"Java",
                percentage:10
            }

        ];
    }

    createContent = () =>{
        let skill;
        if (!this.state.activeSkill) {
            skill = "intro";
        } else {
            skill = this.skills[this.state.activeSkill].name;
        }
        const content = {
            intro: <div  className="text-section">
                <p>I began programming in VBA in order to automate some repetitive tasks in Excel. Since then
                    I've worked on projects in a variety of different programming languages.
                </p>
                <p>Click the links above to see some examples of my work.</p>
            </div>,
            JavaScript: [
                projects[1],
                projects[3],
                projects.andManyMore,
            ],
            'Web development': [
                projects[1],
                projects[2],
                projects.andManyMore,
            ],
            'Google scripts': [
                projects[4],
                projects[5],
                projects.andManyMore,
            ],
            'Python':[
                projects[6]
            ]
            
        }
        return(
            <div className="portfolio-content flex">
                {content[skill]}
            </div>
        );
    };

    clickHandler = (e) => {
        const id = (() => {
            let el = e.target;
            while (!el.id){
                el = el.parentNode;
            }
            return el.id;
        })();
        this.setState({activeSkill:id});
    }

    createSkillSections =() => {
        const skills = this.skills;
        const skillsElements = skills.map((s,i) => {
            return this.createSkillAndProgressBar(s.name,s.percentage,i);
        });
        return skillsElements;
    }
    

    createSkillAndProgressBar = (skillName, percentage, id) => {
        const percentageStr = `${percentage}%`;
        const classNames = (() => {
            let active = "";
            if (this.state.activeSkill) {
                if (parseInt(id) === parseInt(this.state.activeSkill)){
                    active = "active-skill"
                } else {
                    active = "inactive-skill"
                }
            }
            return `button-style skill ${active}`;
        })();
        return (
            <div className={classNames} key={skillName} id={id} onClick={this.clickHandler}>
                <div className="skill-name">{skillName}</div>
                <div className="skill-bar">
                    <div className="skill-bar-fill" style={{width: percentageStr}}></div>
                </div>
            </div>        
        )
    }
    render(){
        return(
            <div>
                <div className="skills-holder" key="1">
                    {this.createSkillSections()}
                </div>
                {this.createContent()}
            </div>
        )
    }
}

export default PortfolioSection;