import React from 'react';
import ContactForm from "./ContactForm";

class ContactSection extends React.Component{
    // constructor(props) {
    //     super(props);
    // }
    render() {
        return(
            <div className="contact-section">
                <h1>Get in touch</h1>
                <div className="contact-container">
                    <div className="contact-text">
                        <p>Feel free to contact me through my social media links below.</p>
                        <p>I am available to collaborate on any projects, big or small, from Excel macros to full websites. Feel free to take a look at my projects page to find out more about what I've been working on recently.</p>
                        <p>Use the contact form or email me at <a href="info@davecook.codes">info@davecook.codes</a>.</p>
                    </div>
                    <ContactForm />
                </div>
            </div>
        )
    }
}

export default ContactSection;